import React, { useMemo, useState } from "react";
import { NavLink } from "react-router-dom";
import {
  LayoutDashboard,
  Users,
  Settings,
  LogOut,
  X,
  Shield,
  FileText,
  Award,
  ClipboardCheck,
  ChevronDown,
  Briefcase,
  CalendarDays,
} from "lucide-react";
import { cn } from "../../utils/cn";
import { Button } from "../common/Button";
import { useAppDispatch } from "../../redux/hooks";
import { logoutUser } from "../../redux/slices/authSlice";
import { usePermission } from "../../hooks/usePermission";
import { PermissionGuard } from "../auth/PermissionGuard";

// Mock navigation items - in real app, these could come from a config or API based on role
const navItems = [
  { icon: LayoutDashboard, label: "Dashboard", path: "/dashboard", permission: "dashboard.view" },
  { icon: Shield, label: "Roles & Permissions", path: "/roles", permission: "roles.view" },
  { icon: Users, label: "Users", path: "/users", permission: "users.view" },
  { icon: Users, label: "Applicants", path: "/applicants", permission: "applicants.view" },
  // { icon: Settings, label: 'Settings', path: '/settings', permission: null },
  {
    icon: FileText,
    label: "Applications",
    path: "/applications",
    permission: "applications.view",
  },
  {
    icon: ClipboardCheck,
    label: "Review",
    path: "/review",
    permission: "applications.view", // Reusing application view permission
  },
  // {
  //   icon: FileText,
  //   label: "Reports",
  //   path: "/reports",
  //   permission: "reports.view",
  // },
  // {
  //   icon: Award,
  //   label: "Merit List",
  //   path: "/merit",
  //   permission: "merit.view",
  // },
];
// Workforce Management nav items
const workforceNavItems = [
  { icon: Briefcase, label: "CHRMS", path: "/workforce/hrm" },
  { icon: ClipboardCheck, label: "My Calendar", path: "/workforce/calendar", permission: "hrm.calendar.manage" },
];

export const Sidebar = ({ isOpen, onClose }) => {
  const dispatch = useAppDispatch();
  const { hasPermission } = usePermission();
  const [openSection, setOpenSection] = useState(null);

  const handleLogout = async () => {
    await dispatch(logoutUser());
  };

  const hasAnyMaster = useMemo(
    () =>
      hasPermission("masters.*") ||
      [
        "masters.districts.view",
        "masters.talukas.view",
        "masters.schemes.view",
        "masters.departments.view",
        "masters.posts.view",
        "masters.document_types.view",
        "masters.application_statuses.view",
        "masters.education_levels.view",
        "masters.categories.view",
        "masters.experience-domains.view",
        "masters.experience_domains.view",
        "masters.skills.view",
        "masters.banners.view",
        "masters.scheme-types.view",
      ].some((perm) => hasPermission(perm)),
    [hasPermission]
  );

  const hasReports = hasPermission("reports.view");
  const hasAnyWorkforce = useMemo(
    () =>
      hasPermission("workforce.*") ||
      workforceNavItems.some((item) => !item.permission || hasPermission(item.permission)),
    [hasPermission]
  );

  const toggleSection = (sectionKey) => {
    setOpenSection((prev) => (prev === sectionKey ? null : sectionKey));
  };

  return (
    <>
      {/* Mobile Backdrop */}
      <div
        className={cn(
          "fixed inset-0 z-40 bg-slate-900/50 backdrop-blur-sm transition-all duration-300 lg:hidden",
          isOpen ? "opacity-100" : "opacity-0 pointer-events-none"
        )}
        onClick={onClose}
      />

      {/* Sidebar */}
      <aside
        className={cn(
          "fixed inset-y-0 left-0 z-50 w-64 transform bg-slate-900 text-white transition-transform duration-300 lg:static lg:translate-x-0 flex flex-col shadow-xl lg:shadow-none border-r border-slate-800",
          isOpen ? "translate-x-0" : "-translate-x-full"
        )}
      >
        <div className="flex h-16 items-center justify-between px-6 border-b border-slate-800 flex-shrink-0 bg-slate-900">
          <div className="flex items-center gap-2">
            <span className="text-lg font-bold tracking-wide text-slate-100">ADMIN PANEL</span>
          </div>
          <button
            onClick={onClose}
            className="lg:hidden p-1 rounded-md text-slate-400 hover:text-white hover:bg-slate-800 transition-colors"
          >
            <X className="h-5 w-5" />
          </button>
        </div>

        <nav className="flex-1 overflow-y-auto scrollbar-hide mt-4 px-3 space-y-1">
          {navItems.map((item) => {
            // Check permissions
            if (item.permission && !hasPermission(item.permission)) return null;

            return (
              <NavLink
                key={item.path}
                to={item.path}
                className={({ isActive }) =>
                  cn(
                    "flex items-center px-3 py-2.5 text-sm font-medium rounded-lg transition-all duration-200 group relative overflow-hidden",
                    isActive
                      ? "bg-gradient-to-r from-blue-600 to-blue-500 text-white shadow-md"
                      : "text-slate-400 hover:bg-slate-800/50 hover:text-slate-100"
                  )
                }
              >
                <item.icon className={cn("mr-3 h-5 w-5 flex-shrink-0 transition-colors", ({ isActive }) => isActive ? "text-white" : "text-slate-400 group-hover:text-slate-300")} />
                <span className="relative z-10">{item.label}</span>
              </NavLink>
            );
          })}

          {/* ── Management Section ── */}
          <div className="pt-4 mt-4 border-t border-slate-800/50">
            <div className="px-3 mb-2 text-xs font-semibold text-slate-500 uppercase tracking-wider">
              Management
            </div>

            {/* Master Data */}
            {hasAnyMaster && (
              <div className="mb-1">
                <button
                  onClick={() => toggleSection("masters")}
                  className={cn(
                    "w-full flex items-center justify-between px-3 py-2.5 text-sm font-medium rounded-lg transition-colors group",
                    openSection === "masters" ? "text-slate-200 bg-slate-800/50" : "text-slate-400 hover:bg-slate-800/30 hover:text-slate-200"
                  )}
                >
                  <div className="flex items-center">
                    <LayoutDashboard className="mr-3 h-5 w-5 flex-shrink-0 text-slate-500 group-hover:text-slate-400" />
                    <span>Master Data</span>
                  </div>
                  <ChevronDown
                    className={cn(
                      "h-4 w-4 transition-transform duration-200 text-slate-500",
                      openSection === "masters" ? "rotate-180 text-slate-400" : ""
                    )}
                  />
                </button>
                <div
                  className={cn(
                    "mt-1 space-y-0.5 overflow-hidden transition-[max-height,opacity] duration-300 ease-in-out",
                    openSection === "masters" ? "max-h-[800px] opacity-100" : "max-h-0 opacity-0"
                  )}
                >
                  <div className="pl-4 border-l border-slate-800 ml-4 my-1 space-y-1">
                    <PermissionGuard permissions="masters.districts.view" fallback={null}>
                      <NavLink
                        to="/masters/districts"
                        className={({ isActive }) =>
                          cn(
                            "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                            isActive
                              ? "text-blue-400 bg-blue-500/10"
                              : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                          )
                        }
                        onClick={() => setOpenSection("masters")}
                      >
                        Districts
                      </NavLink>
                    </PermissionGuard>

                    <PermissionGuard permissions="masters.talukas.view" fallback={null}>
                      <NavLink
                        to="/masters/talukas"
                        className={({ isActive }) =>
                          cn(
                            "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                            isActive
                              ? "text-blue-400 bg-blue-500/10"
                              : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                          )
                        }
                        onClick={() => setOpenSection("masters")}
                      >
                        Talukas
                      </NavLink>
                    </PermissionGuard>

                    <PermissionGuard permissions="masters.scheme-types.view" fallback={null}>
                      <NavLink
                        to="/masters/scheme-types"
                        className={({ isActive }) =>
                          cn(
                            "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                            isActive
                              ? "text-blue-400 bg-blue-500/10"
                              : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                          )
                        }
                        onClick={() => setOpenSection("masters")}
                      >
                        Scheme Types
                      </NavLink>
                    </PermissionGuard>

                    <PermissionGuard permissions="masters.schemes.view" fallback={null}>
                      <NavLink
                        to="/masters/schemes"
                        className={({ isActive }) =>
                          cn(
                            "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                            isActive
                              ? "text-blue-400 bg-blue-500/10"
                              : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                          )
                        }
                        onClick={() => setOpenSection("masters")}
                      >
                        Schemes
                      </NavLink>
                    </PermissionGuard>

                    <PermissionGuard permissions="masters.departments.view" fallback={null}>
                      <NavLink
                        to="/masters/departments"
                        className={({ isActive }) =>
                          cn(
                            "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                            isActive
                              ? "text-blue-400 bg-blue-500/10"
                              : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                          )
                        }
                        onClick={() => setOpenSection("masters")}
                      >
                        Departments
                      </NavLink>
                    </PermissionGuard>

                    <PermissionGuard permissions="masters.document_types.view" fallback={null}>
                      <NavLink
                        to="/masters/document-types"
                        className={({ isActive }) =>
                          cn(
                            "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                            isActive
                              ? "text-blue-400 bg-blue-500/10"
                              : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                          )
                        }
                        onClick={() => setOpenSection("masters")}
                      >
                        Document Types
                      </NavLink>
                    </PermissionGuard>

                    <PermissionGuard permissions="masters.education_levels.view" fallback={null}>
                      <NavLink
                        to="/masters/education-levels"
                        className={({ isActive }) =>
                          cn(
                            "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                            isActive
                              ? "text-blue-400 bg-blue-500/10"
                              : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                          )
                        }
                        onClick={() => setOpenSection("masters")}
                      >
                        Education Levels
                      </NavLink>
                    </PermissionGuard>

                    <PermissionGuard
                      permissions={["masters.experience-domains.view", "masters.experience_domains.view"]}
                      fallback={null}
                    >
                      <NavLink
                        to="/masters/experience-domains"
                        className={({ isActive }) =>
                          cn(
                            "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                            isActive
                              ? "text-blue-400 bg-blue-500/10"
                              : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                          )
                        }
                        onClick={() => setOpenSection("masters")}
                      >
                        Experience Domains
                      </NavLink>
                    </PermissionGuard>

                    <PermissionGuard permissions="masters.skills.view" fallback={null}>
                      <NavLink
                        to="/masters/skills"
                        className={({ isActive }) =>
                          cn(
                            "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                            isActive
                              ? "text-blue-400 bg-blue-500/10"
                              : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                          )
                        }
                        onClick={() => setOpenSection("masters")}
                      >
                        Skills
                      </NavLink>
                    </PermissionGuard>

                    <PermissionGuard permissions="masters.banners.view" fallback={null}>
                      <NavLink
                        to="/masters/banners"
                        className={({ isActive }) =>
                          cn(
                            "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                            isActive
                              ? "text-blue-400 bg-blue-500/10"
                              : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                          )
                        }
                        onClick={() => setOpenSection("masters")}
                      >
                        Banners
                      </NavLink>
                    </PermissionGuard>

                    <PermissionGuard permissions="masters.scheme-types.view" fallback={null}>
                      <NavLink
                        to="/masters/scheme-types"
                        className={({ isActive }) =>
                          cn(
                            "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                            isActive
                              ? "text-blue-400 bg-blue-500/10"
                              : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                          )
                        }
                        onClick={() => setOpenSection("masters")}
                      >
                        Scheme Types
                      </NavLink>
                    </PermissionGuard>

                    <PermissionGuard permissions="masters.posts.view" fallback={null}>
                      <NavLink
                        to="/masters/posts"
                        className={({ isActive }) =>
                          cn(
                            "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                            isActive
                              ? "text-blue-400 bg-blue-500/10"
                              : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                          )
                        }
                        onClick={() => setOpenSection("masters")}
                      >
                        Posts
                      </NavLink>
                    </PermissionGuard>
                  </div>
                </div>
              </div>
            )}

            {/* Reports */}
            {hasReports && (
              <div className="mb-1">
                <button
                  onClick={() => toggleSection("reports")}
                  className={cn(
                    "w-full flex items-center justify-between px-3 py-2.5 text-sm font-medium rounded-lg transition-colors group",
                    openSection === "reports" ? "text-slate-200 bg-slate-800/50" : "text-slate-400 hover:bg-slate-800/30 hover:text-slate-200"
                  )}
                >
                  <div className="flex items-center">
                    <FileText className="mr-3 h-5 w-5 flex-shrink-0 text-slate-500 group-hover:text-slate-400" />
                    <span>Reports</span>
                  </div>
                  <ChevronDown
                    className={cn(
                      "h-4 w-4 transition-transform duration-200 text-slate-500",
                      openSection === "reports" ? "rotate-180 text-slate-400" : ""
                    )}
                  />
                </button>
                <div
                  className={cn(
                    "mt-1 space-y-0.5 overflow-hidden transition-[max-height,opacity] duration-300 ease-in-out",
                    openSection === "reports" ? "max-h-[400px] opacity-100" : "max-h-0 opacity-0"
                  )}
                >
                  <div className="pl-4 border-l border-slate-800 ml-4 my-1 space-y-1">
                    <NavLink
                      to="/reports/post-wise"
                      className={({ isActive }) =>
                        cn(
                          "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                          isActive
                            ? "text-blue-400 bg-blue-500/10"
                            : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                        )
                      }
                      onClick={() => setOpenSection("reports")}
                    >
                      Post Wise Report
                    </NavLink>

                    <NavLink
                      to="/reports/district-wise"
                      className={({ isActive }) =>
                        cn(
                          "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                          isActive
                            ? "text-blue-400 bg-blue-500/10"
                            : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                        )
                      }
                      onClick={() => setOpenSection("reports")}
                    >
                      District Wise Report
                    </NavLink>

                    <NavLink
                      to="/reports/component-wise"
                      className={({ isActive }) =>
                        cn(
                          "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                          isActive
                            ? "text-blue-400 bg-blue-500/10"
                            : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                        )
                      }
                      onClick={() => setOpenSection("reports")}
                    >
                      OSC Wise Report
                    </NavLink>

                    <NavLink
                      to="/reports/hub-wise"
                      className={({ isActive }) =>
                        cn(
                          "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                          isActive
                            ? "text-blue-400 bg-blue-500/10"
                            : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                        )
                      }
                      onClick={() => setOpenSection("reports")}
                    >
                      Hub Wise Report
                    </NavLink>

                    <NavLink
                      to="/reports/post-selected"
                      className={({ isActive }) =>
                        cn(
                          "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                          isActive
                            ? "text-blue-400 bg-blue-500/10"
                            : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                        )
                      }
                      onClick={() => setOpenSection("reports")}
                    >
                      Allotment Report
                    </NavLink>

                    <NavLink
                      to="/reports/final-list"
                      className={({ isActive }) =>
                        cn(
                          "flex items-center px-3 py-2 text-sm font-medium rounded-md transition-colors",
                          isActive
                            ? "text-blue-400 bg-blue-500/10"
                            : "text-slate-500 hover:text-slate-300 hover:bg-slate-800/30"
                        )
                      }
                      onClick={() => setOpenSection("reports")}
                    >
                      Final Report List
                    </NavLink> 

                  </div>
                </div>
              </div>
            )}

          </div>

          {/* ── Workforce Management Section ── */}
          {hasAnyWorkforce && (
            <div className="pt-4 mt-4 border-t border-slate-800/50">
              <div className="px-3 mb-2 text-xs font-semibold text-slate-500 uppercase tracking-wider">
                Workforce Management
              </div>

              {workforceNavItems.map((item) => {
                if (item.permission && !hasPermission(item.permission)) return null;

                return (
                  <NavLink
                    key={item.path}
                    to={item.path}
                    className={({ isActive }) =>
                      cn(
                        "flex items-center px-3 py-2.5 text-sm font-medium rounded-lg transition-all duration-200 group relative overflow-hidden",
                        isActive
                          ? "bg-gradient-to-r from-blue-600 to-blue-500 text-white shadow-md"
                          : "text-slate-400 hover:bg-slate-800/50 hover:text-slate-100"
                      )
                    }
                  >
                    <item.icon className="mr-3 h-5 w-5 flex-shrink-0 transition-colors" />
                    <span className="relative z-10">{item.label}</span>
                  </NavLink>
                );
              })}
            </div>
          )}
        </nav>

        <div className="flex-shrink-0 p-4 border-t border-slate-800 bg-slate-900">
          <Button
            variant="ghost"
            className="w-full justify-start text-slate-400 hover:text-white hover:bg-slate-800 transition-colors"
            leftIcon={<LogOut className="h-5 w-5" />}
            onClick={handleLogout}
          >
            Logout
          </Button>
        </div>
      </aside>
    </>
  );
};