import React, { Suspense } from 'react';
import { createBrowserRouter, RouterProvider, Navigate } from 'react-router-dom';
import { Layout } from '../components/layout/Layout';
import { AuthGuard } from '../components/auth/AuthGuard';
import Login from '../pages/auth/Login';

// Lazy load pages for performance
const Dashboard = React.lazy(() => import('../pages/Dashboard'));
const UserList = React.lazy(() => import('../pages/users/UserList'));
const UserAdd = React.lazy(() => import('../pages/users/UserAdd'));
const UserEdit = React.lazy(() => import('../pages/users/UserEdit'));
const UserView = React.lazy(() => import('../pages/users/UserView'));
const RoleList = React.lazy(() => import('../pages/roles/RoleList'));
const RoleAdd = React.lazy(() => import('../pages/roles/RoleAdd'));
const RoleEdit = React.lazy(() => import('../pages/roles/RoleEdit'));
const ChangePassword = React.lazy(() => import('../pages/auth/ChangePassword'));
const MasterRoutes = React.lazy(() => import('../routes/masterRoutes'));
const ReportRoutes = React.lazy(() => import('../routes/reportRoutes'));
const WorkforceRoutes = React.lazy(() => import('../routes/workforceRoutes'));
const ApplicationList = React.lazy(() => import('../pages/applications/ApplicationList'));
const ApplicationView = React.lazy(() => import('../pages/applications/ApplicationView'));
const MeritList = React.lazy(() => import('../pages/merit/MeritList'));
const PostReviewList = React.lazy(() => import('../pages/review/PostReviewList'));
const PostApplications = React.lazy(() => import('../pages/review/PostApplications'));
const StageWiseReport = React.lazy(() => import('../pages/review/StageWiseReport'));
const ApplicantList = React.lazy(() => import('../pages/applicants/ApplicantList'));
const ApplicantView = React.lazy(() => import('../pages/applicants/ApplicantView'));

const router = createBrowserRouter([
    {
      path: '/login',
      element: <Login />,
    },
    {
        path: '/',
      element: (
        <AuthGuard>
          <Layout />
        </AuthGuard>
      ),
      children: [
        {
          index: true,
          element: <Navigate to="/dashboard" replace />,
        },
        {
                path: 'dashboard',
          element: (
            <Suspense fallback={<div className="p-6">Loading...</div>}>
              <Dashboard />
            </Suspense>
          ),
        },
        {
                path: 'users',
          children: [
            {
              index: true,
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <UserList />
                </Suspense>
              ),
            },
            {
                        path: 'add',
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <UserAdd />
                </Suspense>
              ),
            },
            {
                        path: 'edit/:id',
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <UserEdit />
                </Suspense>
              ),
            },
            {
                        path: 'view/:id',
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <UserView />
                </Suspense>
              ),
            },
          ],
        },
        {
                path: 'roles',
          children: [
            {
              index: true,
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <RoleList />
                </Suspense>
              ),
            },
            {
                        path: 'add',
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <RoleAdd />
                </Suspense>
              ),
            },
            {
                        path: 'edit/:id',
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <RoleEdit />
                </Suspense>
              ),
            },
          ],
        },
        {
                path: 'applications',
          children: [
            {
              index: true,
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <ApplicationList />
                </Suspense>
              ),
            },
            {
                        path: ':id',
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <ApplicationView />
                </Suspense>
              ),
            },
          ],
        },
        {
                path: 'applicants',
          children: [
            {
              index: true,
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <ApplicantList />
                </Suspense>
              ),
            },
            {
                        path: ':id',
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <ApplicantView />
                </Suspense>
              ),
            },
          ],
        },
        {
                path: 'review',
          children: [
            {
              index: true,
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <PostReviewList />
                </Suspense>
              ),
            },
            {
                        path: 'posts/:postId',
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <PostApplications />
                </Suspense>
              ),
            },
            {
                        path: 'posts/:postId/stage-report',
              element: (
                <Suspense fallback={<div className="p-6">Loading...</div>}>
                  <StageWiseReport />
                </Suspense>
              ),
            },
          ],
        },
        {
                path: 'merit',
          element: (
            <Suspense fallback={<div className="p-6">Loading...</div>}>
              <MeritList />
            </Suspense>
          ),
        },
        {
                path: 'change-password',
          element: (
            <Suspense fallback={<div className="p-6">Loading...</div>}>
              <ChangePassword />
            </Suspense>
          ),
        },
        {
                path: 'masters/*',
          element: (
            <Suspense fallback={<div className="p-6">Loading...</div>}>
              <MasterRoutes />
            </Suspense>
          ),
        },
        {
                path: 'reports/*',
          element: (
            <Suspense fallback={<div className="p-6">Loading...</div>}>
              <ReportRoutes />
            </Suspense>
          ),
        },
        {
          path: "workforce/*",
          element: (
            <Suspense fallback={<div className="p-6">Loading...</div>}>
              <WorkforceRoutes />
            </Suspense>
          ),
        },
        {
          path: '*',
          element: <Navigate to="/dashboard" replace />,
        },
      ],
    },
], {
  basename: '/admin'
});

export const AppRouter = () => {
  return <RouterProvider router={router} />;
};
